import{u as d}from"./BQ3rnpRR.js";import{e as t,c,p as s,o as v,_ as e}from"./jDLesiTG.js";const i={class:"about-us-page"},n=t({__name:"about-us",setup(l){return d({title:"关于我们 - 凡图拉",meta:[{name:"description",content:"了解凡图拉的使命愿景和核心优势，我们致力于为用户提供优质服务。"},{name:"keywords",content:"凡图拉,关于我们,我们的使命,我们的优势,企业愿景"}]}),(o,a)=>(v(),c("div",i,[...a[0]||(a[0]=[s('<div class="page-content" data-v-81cd6109><div class="content-container" data-v-81cd6109><div class="header-section" data-v-81cd6109><h1 class="main-title" data-v-81cd6109>关于我们</h1><h2 class="sub-title" data-v-81cd6109>我们的使命</h2></div><div class="content-section" data-v-81cd6109><div class="mission-section" data-v-81cd6109><h3 class="section-title" data-v-81cd6109>我们的使命</h3><div class="section-content" data-v-81cd6109><p class="content-paragraph" data-v-81cd6109> 在全球数字化浪潮推动下，人们对跨境数字权益与订阅服务的需求日益增长，而服务渠道、平台限制、地域门槛却仍然存在。凡图拉的使命，就是要打破这些壁垒，让数字服务权益触手可及、轻松获取。我们致力于打造一个安全、灵活、无需实名即可使用的数字化服务平台，帮助用户轻松获取海外订阅、虚拟会员权益、礼品卡与数字化技术支持。无论你身处何地，只需注册邮箱账户，即可进入一个稳定高效的虚拟服务生态。未来，我们希望成为华语用户首选的全球数字权益服务平台，让每一次服务订阅、每一张礼品卡、每一次权益兑换，都变得简单可靠、有温度。 </p></div></div><div class="advantages-section" data-v-81cd6109><h3 class="section-title" data-v-81cd6109>我们的优势</h3><div class="advantages-list" data-v-81cd6109><div class="advantage-item" data-v-81cd6109><div class="advantage-icon" data-v-81cd6109>💎</div><div class="advantage-content" data-v-81cd6109><h4 class="advantage-title" data-v-81cd6109>五年以上稳定运营经验</h4><p class="advantage-desc" data-v-81cd6109> 自2019年起稳步发展，凡图拉拥有成熟的运营体系和用户信任基础，是市场中为数不多持续运营超过五年的数字化服务平台。 </p></div></div><div class="advantage-item" data-v-81cd6109><div class="advantage-icon" data-v-81cd6109>💎</div><div class="advantage-content" data-v-81cd6109><h4 class="advantage-title" data-v-81cd6109>极简账户机制，无需实名注册</h4><p class="advantage-desc" data-v-81cd6109> 平台仅需邮箱注册登录，无需手机号、无需实名验证，轻松开启安全便捷的服务体验，深受用户欢迎。 </p></div></div><div class="advantage-item" data-v-81cd6109><div class="advantage-icon" data-v-81cd6109>💎</div><div class="advantage-content" data-v-81cd6109><h4 class="advantage-title" data-v-81cd6109>支持多种订阅方式与售后保障</h4><p class="advantage-desc" data-v-81cd6109> 支持多种主流便捷的数字化订阅/兑换方式，支持平台服务额度返还（不具备货币兑换或转账功能），满足灵活的用户场景。 </p></div></div><div class="advantage-item" data-v-81cd6109><div class="advantage-icon" data-v-81cd6109>💎</div><div class="advantage-content" data-v-81cd6109><h4 class="advantage-title" data-v-81cd6109>权益订阅+礼品卡+通用权益卡 多业务融合</h4><p class="advantage-desc" data-v-81cd6109> 从数字化权益服务业务出发，逐步拓展至麦当劳、Netflix 等主流平台的权益包发售，以及通用权益卡服务，打造多元化数字服务生态。 </p></div></div><div class="advantage-item" data-v-81cd6109><div class="advantage-icon" data-v-81cd6109>💎</div><div class="advantage-content" data-v-81cd6109><h4 class="advantage-title" data-v-81cd6109>自动交付+双线售后体系</h4><p class="advantage-desc" data-v-81cd6109> 平台支持自动交付系统，并提供微信、Telegram、WhatsApp 客服支持，实现全天候响应与人工售后处理。 </p></div></div><div class="advantage-item" data-v-81cd6109><div class="advantage-icon" data-v-81cd6109>💎</div><div class="advantage-content" data-v-81cd6109><h4 class="advantage-title" data-v-81cd6109>品牌定位清晰且合规意识强</h4><p class="advantage-desc" data-v-81cd6109> 商品页面均采用合规化展示方式，规避高风险描述与敏感内容，确保平台在运营中的长期稳定性与可持续性。 </p></div></div></div></div></div></div></div>',1)])]))}}),h=e(n,[["__scopeId","data-v-81cd6109"]]);export{h as default};
